// ─── Editable field helpers ───────────────────────────────────────────────────

const EDIT_INPUT_STYLE = {
  fontSize: 13.5,
  color: '#1B2840',
  fontWeight: 600,
  background: '#F6F8FC',
  border: '1px solid #0094FF',
  borderRadius: 6,
  padding: '2px 6px',
  outline: 'none',
  width: '100%',
}

function EditText({
  value,
  onSave,
  placeholder = '—',
  multiline = false,
  textStyle,
}: {
  value: string | null | undefined
  onSave: (v: string) => void
  placeholder?: string
  multiline?: boolean
  textStyle?: React.CSSProperties
}) {
  const [editing, setEditing] = useState(false)
  const [draft, setDraft] = useState(value ?? '')
  const ref = useRef<HTMLInputElement & HTMLTextAreaElement>(null)

  useEffect(() => { if (editing) ref.current?.focus() }, [editing])
  // sync if external value changes while not editing
  useEffect(() => { if (!editing) setDraft(value ?? '') }, [value, editing])

  function commit() {
    setEditing(false)
    if (draft !== (value ?? '')) onSave(draft)
  }
  function cancel() { setEditing(false); setDraft(value ?? '') }

  if (editing) {
    const sharedProps = {
      value: draft,
      onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => setDraft(e.target.value),
      onBlur: commit,
      style: { ...EDIT_INPUT_STYLE, resize: 'none' as const },
    }
    if (multiline) {
      return (
        <textarea
          ref={ref}
          rows={3}
          onKeyDown={(e) => { if (e.key === 'Escape') cancel() }}
          {...sharedProps}
        />
      )
    }
    return (
      <input
        ref={ref}
        type="text"
        onKeyDown={(e) => { if (e.key === 'Enter') commit(); if (e.key === 'Escape') cancel() }}
        {...sharedProps}
      />
    )
  }

  return (
    <span
      onClick={() => { setDraft(value ?? ''); setEditing(true) }}
      className="group cursor-text rounded px-1 -ml-1 hover:bg-[#F6F8FC] transition-colors inline-block"
      title="Click to edit"
      style={textStyle ?? { fontSize: 13.5, color: value ? '#1B2840' : '#94A0B5', fontWeight: 600 }}
    >
      {value || placeholder}
    </span>
  )
}

function EditSelect({
  value,
  options,
  onSave,
  renderValue,
}: {
  value: string
  options: Array<{ value: string; label: string }>
  onSave: (v: string) => void
  renderValue: (v: string) => React.ReactNode
}) {
  const [editing, setEditing] = useState(false)
  const [draft, setDraft] = useState(value)
  const ref = useRef<HTMLSelectElement>(null)

  useEffect(() => { if (editing) ref.current?.focus() }, [editing])
  useEffect(() => { if (!editing) setDraft(value) }, [value, editing])

  function commit(v: string) {
    setEditing(false)
    if (v !== value) onSave(v)
  }

  if (editing) {
    return (
      <select
        ref={ref}
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={() => commit(draft)}
        onKeyDown={(e) => { if (e.key === 'Enter') commit(draft); if (e.key === 'Escape') { setEditing(false); setDraft(value) } }}
        style={{ ...EDIT_INPUT_STYLE, fontWeight: 600 }}
        autoFocus
      >
        {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
      </select>
    )
  }

  return (
    <span
      onClick={() => { setDraft(value); setEditing(true) }}
      className="cursor-pointer rounded px-1 -ml-1 hover:bg-[#F6F8FC] transition-colors inline-block"
      title="Click to edit"
    >
      {renderValue(value)}
    </span>
  )
}

