        onBlur={commit}
        onKeyDown={(e) => { if (e.key === 'Enter') commit(); if (e.key === 'Escape') { setEditing(false); setDraft(value) } }}
        style={{ ...EDIT_INPUT_STYLE, width: 'auto' }}
      />
    )
  }

  return (
    <span
