  'closure_reason',
  'cover_url',
  'clickup_url',
  'clickup_list_name',
  'clickup_parent_id',
  'clickup_top_level_parent_id',
  'clickup_status',
  'clickup_status_type',
  'clickup_status_color',
  'clickup_status_order',
  'clickup_created_at',
  'clickup_updated_at',
  'clickup_closed_at',
  'clickup_start_at',
  'clickup_due_at',
  { stage: ['id', 'name'] },
