import type { BusinessUnit } from '@/domain/products/types'

export type Screen =
  | 'home'
  | 'pipeline'
  | 'projects'
  | 'designs'
  | 'collections'
  | 'orders'
  | 'accounts'
  | 'reports'
  | 'submissions'
  | 'samples'
  | 'revisions'
  | 'schedule'
  | 'notes'
  | 'people'
  | 'mywork'
