export function MyWorkPage() {
  const { user, loading: authLoading } = useAuth()
  const [activeProduct, setActiveProduct] = useState<ProductSummary | null>(null)
  const [products, setProducts] = useState<ProductSummary[]>([])
  const [revisions, setRevisions] = useState<RevisionRequest[]>([])
  const [loadedUserId, setLoadedUserId] = useState<string | null>(null)
  const [collapsed, setCollapsed] = useState<Set<string>>(new Set())
  const userId = user?.id ?? null
  const roleId = user?.role?.id ?? null

  useEffect(() => {
    if (!userId) return
    let active = true
    Promise.all([fetchMyWorkProducts(userId, roleId), fetchMyRevisionWork(userId)])
      .then(async ([rows, revisionRows]) => {
        if (!active) return
        const hydrated = await hydrateProductSummaryRollups(rows.map(productToSummary))
        if (!active) return
        setProducts(hydrated)
        setRevisions(revisionRows)
        setLoadedUserId(userId)
      })
      .catch(() => {
        if (!active) return
        setProducts([])
        setRevisions([])
        setLoadedUserId(userId)
      })
    return () => { active = false }
  }, [roleId, userId])

  const visibleProducts = useMemo(() => (userId === loadedUserId ? products : []), [loadedUserId, products, userId])
  const loading = authLoading || (Boolean(userId) && userId !== loadedUserId)

  const groups = useMemo(() => {
    const map = new Map<string, ProductSummary[]>()
    for (const product of visibleProducts) {
      const key = product.stageName || 'No stage'
      ;(map.get(key) ?? map.set(key, []).get(key)!).push(product)
    }
    return [...map.entries()].map(([stage, items]) => ({ stage, items }))
  }, [visibleProducts])

  function toggleCollapse(key: string) {
    setCollapsed((prev) => {
      const next = new Set(prev)
      if (next.has(key)) next.delete(key)
      else next.add(key)
      return next
    })
  }

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>
        Loading your work...
      </div>
    )
  }

  return (
    <>
      <div className="h-full overflow-y-auto px-8 py-7">
        <div className="mb-7">
          <h2 className="font-extrabold" style={{ fontSize: 21, color: '#1B2840', letterSpacing: '-0.02em' }}>
            My work
          </h2>
          <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
            Work owned by {userDisplayName(user)} · {visibleProducts.length} product{visibleProducts.length === 1 ? '' : 's'} · {revisions.length} revision{revisions.length === 1 ? '' : 's'}
          </p>
        </div>

        {visibleProducts.length === 0 && revisions.length === 0 ? (
          <div className="rounded-xl border px-5 py-8 text-[13.5px]" style={{ borderColor: '#EAEEF5', color: '#5A6883' }}>
            No direct assignments, lifecycle-owned products, or revision requests are assigned to you yet.
          </div>
        ) : (
          <div className="space-y-4">
            {groups.map(({ stage, items }) => {
              const stageStyle = resolveStageColor(stage)
              const isCollapsed = collapsed.has(stage)

              return (
                <div key={stage} className="overflow-hidden rounded-xl" style={{ border: '1px solid #EAEEF5' }}>
                  <div
                    className="flex cursor-pointer items-center gap-2.5 px-4 py-3 transition-colors hover:bg-[#F6F8FC]"
                    style={{ background: '#F6F8FC', borderBottom: isCollapsed ? 'none' : '1px solid #EAEEF5' }}
                    onClick={() => toggleCollapse(stage)}
                  >
                    <ChevronRight
                      className="size-4 transition-transform"
                      style={{ color: '#5A6883', transform: isCollapsed ? 'rotate(0deg)' : 'rotate(90deg)' }}
                    />
                    <span className="size-2 rounded-full" style={{ background: stageStyle.dot }} />
                    <span className="text-[13px] font-bold" style={{ color: '#1B2840' }}>{stage}</span>
                    <span className="rounded px-1.5 py-0.5 text-[11px] font-semibold" style={{ background: '#EAEEF5', color: '#5A6883' }}>
                      {items.length}
                    </span>
                  </div>

                  {!isCollapsed && items.map((product) => (
                    <MyWorkRow key={product.id} product={product} onOpen={setActiveProduct} />
                  ))}
                </div>
              )
            })}
            {revisions.length > 0 && (
              <div className="overflow-hidden rounded-xl" style={{ border: '1px solid #EAEEF5' }}>
                <div className="flex items-center gap-2.5 px-4 py-3" style={{ background: '#F6F8FC', borderBottom: '1px solid #EAEEF5' }}>
                  <FilePenLine className="size-4" style={{ color: '#5A6883' }} />
                  <span className="text-[13px] font-bold" style={{ color: '#1B2840' }}>Revision requests</span>
                  <span className="rounded px-1.5 py-0.5 text-[11px] font-semibold" style={{ background: '#EAEEF5', color: '#5A6883' }}>
                    {revisions.length}
                  </span>
                </div>
                {revisions.map((revision) => (
                  <RevisionWorkRow key={revision.id} revision={revision} />
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      <TaskDetailModal task={activeProduct} onClose={() => setActiveProduct(null)} />
    </>
  )
}

function RevisionWorkRow({ revision }: { revision: RevisionRequest }) {
  const product = revision.product && typeof revision.product === 'object' ? productToSummary(revision.product) : null
  return (
    <div className="flex items-center gap-3 px-4 py-3" style={{ borderBottom: '1px solid #EAEEF5' }}>
      <div className="flex size-[24px] shrink-0 items-center justify-center rounded-lg" style={{ background: '#ECE2F8' }}>
        <FilePenLine className="size-3.5" style={{ color: '#6B54C9' }} />
      </div>
      <div className="min-w-0 flex-1">
        <p className="line-clamp-1 text-[13.5px] font-medium" style={{ color: '#1B2840' }}>
          {product ? product.title : 'Revision request'}
        </p>
        <p className="mt-0.5 line-clamp-1 text-[12px]" style={{ color: '#5A6883' }}>
          {[titleCase(revision.source), titleCase(revision.status), revision.body].filter(Boolean).join(' · ')}
        </p>
      </div>
      <span className="shrink-0 text-[12px]" style={{ color: '#94A0B5' }}>
        {formatDate(revision.due_at)}
      </span>
    </div>
  )
}

function MyWorkRow({ product, onOpen }: { product: ProductSummary; onOpen: (p: ProductSummary) => void }) {
  const catColors = CATEGORY_COLORS[product.category]
  const licMeta = product.licensorName ? LICENSOR_META[product.licensorName] : null

  return (
    <div
      className="flex cursor-pointer items-center gap-3 px-4 py-3 transition-colors hover:bg-[#F6F8FC]"
      style={{ borderBottom: '1px solid #EAEEF5' }}
      onClick={() => onOpen(product)}
    >
      <div
        className="flex size-[24px] shrink-0 items-center justify-center rounded-lg"
        style={{ background: catColors?.bg ?? '#F6F8FC' }}
      >
        <span className="text-[8px] font-black" style={{ color: catColors?.accent ?? '#5A6883' }}>
          {CATEGORY_ICONS[product.category] ?? 'PRD'}
        </span>
      </div>
      <div className="min-w-0 flex-1">
        <p className="line-clamp-1 text-[13.5px] font-medium" style={{ color: '#1B2840' }}>
          {[product.code, product.title].filter(Boolean).join(' · ')}
        </p>
        <p className="mt-0.5 line-clamp-1 text-[12px]" style={{ color: '#5A6883' }}>
          {[product.businessUnit, product.retailerName, product.buyerName, product.nextAction].filter(Boolean).join(' · ')}
        </p>
      </div>
      {licMeta && (
        <span className="shrink-0 rounded-full px-2 py-0.5 text-[10.5px] font-bold text-white" style={{ background: licMeta.gradient }}>
          {licMeta.letter} {product.licensorName}
        </span>
      )}
      {product.priority !== 'normal' && (
        <Flag className="size-3.5 shrink-0" style={{ color: product.priority === 'urgent' ? '#E0483A' : '#F2A23C' }} />
      )}
      {product.due && (
        <span className="shrink-0 text-[12px]" style={{ color: product.dueOver ? '#D2502B' : '#94A0B5' }}>
          {product.due}
        </span>
      )}
    </div>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { ReceiptText, Search } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import type { Order, Product } from '@/lib/types'
import { useAppState } from '@/lib/appState'
import { fetchOrders } from './api'

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function formatDate(iso: string | null): string {
  if (!iso) return 'No order date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function productObject(order: Order): Product | null {
  return order.product && typeof order.product === 'object' ? order.product : null
}

export function OrdersPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [orders, setOrders] = useState<Order[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchOrders({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setOrders(next) })
      .catch((error) => {
        console.error(error)
        if (active) setOrders([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const grouped = useMemo(() => {
    const map = new Map<string, Order[]>()
    for (const order of orders) {
      const product = productObject(order)
      const retailer = relationName(order.retailer) ?? relationName(product?.project && typeof product.project === 'object' ? product.project.retailer : null) ?? 'No retailer'
      ;(map.get(retailer) ?? map.set(retailer, []).get(retailer)!).push(order)
    }
    return [...map.entries()].sort(([a], [b]) => a.localeCompare(b))
  }, [orders])

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>
        Loading orders...
      </div>
    )
  }

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div>
            <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>
              Orders
            </h1>
            <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
              {orders.length.toLocaleString()} purchase-order record{orders.length === 1 ? '' : 's'} in this view
            </p>
          </div>
          <div className="flex items-center gap-2 rounded-lg border px-3 py-2 text-[12.5px]" style={{ borderColor: '#EAEEF5', color: '#5A6883' }}>
            <Search className="size-4" />
            <span>{searchQuery.trim() ? `Searching "${searchQuery.trim()}"` : 'Use sidebar search'}</span>
          </div>
        </div>

        {orders.length === 0 ? (
          <div className="rounded-lg border px-5 py-10 text-center text-[13.5px]" style={{ borderColor: '#EAEEF5', color: '#94A0B5' }}>
            No orders match this filter.
          </div>
        ) : (
          <div className="space-y-6">
            {grouped.map(([retailer, rows]) => (
              <section key={retailer}>
                <div className="mb-3 flex items-center gap-2">
                  <h2 className="text-[14px] font-bold" style={{ color: '#1B2840' }}>{retailer}</h2>
                  <span className="rounded px-1.5 py-0.5 text-[11px] font-semibold" style={{ background: '#EAEEF5', color: '#5A6883' }}>
                    {rows.length}
                  </span>
                </div>
                <div className="overflow-hidden rounded-lg border" style={{ borderColor: '#EAEEF5' }}>
                  <table className="w-full text-left">
                    <thead>
                      <tr style={{ borderBottom: '1px solid #EAEEF5' }}>
                        {(['Order', 'Product', 'Project', 'Buyer', 'Date', 'Qty'] as const).map((header) => (
                          <th
                            key={header}
                            className="bg-white px-4 py-3 text-[11px] font-bold uppercase tracking-[0.04em]"
                            style={{ color: '#94A0B5', width: header === 'Product' ? '28%' : undefined }}
                          >
                            {header}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {rows.map((order) => <OrderRow key={order.id} order={order} />)}
                    </tbody>
                  </table>
                </div>
              </section>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

function OrderRow({ order }: { order: Order }) {
  const product = productObject(order)
  const summary = product ? productToSummary(product) : null
  const project = product?.project && typeof product.project === 'object' ? product.project : null
  const buyer = relationName(order.buyer) ?? relationName(project?.buyer) ?? 'No buyer'

  return (
    <tr className="transition-colors hover:bg-[#F6F8FC]" style={{ borderBottom: '1px solid #EAEEF5' }}>
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <span className="flex size-7 shrink-0 items-center justify-center rounded-lg" style={{ background: '#FBEBD3' }}>
            <ReceiptText className="size-3.5" style={{ color: '#C8942A' }} />
          </span>
          <span className="text-[13px] font-semibold" style={{ color: '#1B2840' }}>
            {order.order_number ?? '(no order number)'}
          </span>
        </div>
      </td>
      <td className="px-4 py-3">
        <div className="min-w-0">
          <p className="line-clamp-1 text-[13px] font-semibold" style={{ color: '#1B2840' }}>
            {summary ? [summary.code, summary.title].filter(Boolean).join(' · ') : 'No product linked'}
          </p>
          <p className="mt-0.5 line-clamp-1 text-[12px]" style={{ color: '#5A6883' }}>
            {[summary?.businessUnit, summary?.productTypeName, summary?.stageName].filter(Boolean).join(' · ') || 'No product context'}
          </p>
        </div>
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {summary?.projectTitle ?? 'No project'}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {buyer}
      </td>
      <td className="px-4 py-3 text-[13px]" style={{ color: '#5A6883' }}>
        {formatDate(order.order_date)}
      </td>
      <td className="px-4 py-3 text-[13px] font-semibold" style={{ color: '#1B2840' }}>
        {order.quantity?.toLocaleString() ?? '—'}
      </td>
    </tr>
  )
}

import { useEffect, useMemo, useState } from 'react'
import { ArrowRight, Camera, Factory, FlaskConical, TriangleAlert } from 'lucide-react'
import { productToSummary } from '@/domain/products/adapters'
import { useAppState } from '@/lib/appState'
import type { DirectusUser, Product, ProductSample } from '@/lib/types'
import { fetchSamples, updateSampleStatus } from '@/features/workflow/api'

function titleCase(value: string | null | undefined) {
  return (value ?? 'unknown').replaceAll('_', ' ').replace(/\b\w/g, (c) => c.toUpperCase())
}

function formatDate(iso: string | null | undefined) {
  if (!iso) return 'No date'
  return new Date(iso).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })
}

function relationName(value: unknown): string | null {
  if (!value || typeof value === 'string') return null
  if (typeof value === 'object' && 'name' in value && typeof value.name === 'string') return value.name
  if (typeof value === 'object' && 'title' in value && typeof value.title === 'string') return value.title
  return null
}

function userName(value: string | DirectusUser | null | undefined) {
  if (!value || typeof value === 'string') return null
  return [value.first_name, value.last_name].filter(Boolean).join(' ') || value.email
}

function productObject(row: ProductSample): Product | null {
  return row.product && typeof row.product === 'object' ? row.product : null
}

const STATUS_STYLE: Record<string, { bg: string; color: string }> = {
  needed: { bg: '#FBEBD3', color: '#9A6400' },
  requested: { bg: '#DEEBFB', color: '#2563A8' },
  in_factory: { bg: '#DEEBFB', color: '#2563A8' },
  received: { bg: '#D8EFF5', color: '#0E7490' },
  under_internal_review: { bg: '#ECE2F8', color: '#6B54C9' },
  sent_to_buyer: { bg: '#D8EFE7', color: '#14745D' },
  sent_to_licensor: { bg: '#D8EFE7', color: '#14745D' },
  approved: { bg: '#D8EFE7', color: '#14745D' },
  revision_needed: { bg: '#FBE2D8', color: '#9E3B1C' },
}

function statusStyle(status: string | null | undefined) {
  return STATUS_STYLE[status ?? ''] ?? { bg: '#EEF1F6', color: '#5A6883' }
}

export function SamplesPage() {
  const { businessUnit, searchQuery } = useAppState()
  const [rows, setRows] = useState<ProductSample[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    let active = true
    fetchSamples({ businessUnit, search: searchQuery })
      .then((next) => { if (active) setRows(next) })
      .catch((error) => {
        console.error(error)
        if (active) setRows([])
      })
      .finally(() => { if (active) setLoading(false) })
    return () => { active = false }
  }, [businessUnit, searchQuery])

  const groups = useMemo(() => {
    const map = new Map<string, ProductSample[]>()
    for (const row of rows) {
      const key = titleCase(row.status)
      ;(map.get(key) ?? map.set(key, []).get(key)!).push(row)
    }
    return [...map.entries()]
  }, [rows])

  if (loading) return <div className="flex h-full items-center justify-center text-sm" style={{ color: '#94A0B5' }}>Loading samples...</div>

  return (
    <div className="h-full overflow-y-auto bg-white">
      <div className="mx-auto flex max-w-[1480px] flex-col gap-5 px-7 py-6">
        <div>
          <h1 className="text-[22px] font-extrabold leading-tight" style={{ color: '#1B2840' }}>Samples / Factory</h1>
          <p className="mt-1 text-[13.5px]" style={{ color: '#5A6883' }}>
            Factory, buyer, licensor, PPS, production, and resample tracking
          </p>
        </div>

        {rows.length === 0 ? (
          <EmptyState label="No sample records match this filter yet." />
        ) : (
          <div className="space-y-6">
            {groups.map(([status, items]) => (
              <section key={status}>
                <GroupHeader label={status} count={items.length} />
                <div className="grid gap-3 xl:grid-cols-2">
                  {items.map((row) => (
                    <SampleCard
                      key={row.id}
                      row={row}
                      onUpdated={(next) => setRows((prev) => prev.map((item) => item.id === next.id ? { ...item, ...next } : item))}
                    />
                  ))}
                </div>
              </section>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}

function nextSampleStep(status: string | null | undefined): { status: string; label: string } | null {
  if (!status || status === 'needed') return { status: 'requested', label: 'Request' }
  if (status === 'requested') return { status: 'in_factory', label: 'In factory' }
  if (status === 'in_factory') return { status: 'received', label: 'Received' }
  if (status === 'received' || status === 'under_internal_review') return { status: 'approved', label: 'Approve' }
  return null
}

function SampleCard({ row, onUpdated }: { row: ProductSample; onUpdated: (row: ProductSample) => void }) {
  const product = productObject(row)
  const summary = product ? productToSummary(product) : null
  const status = statusStyle(row.status)
  const [busy, setBusy] = useState(false)
  const next = nextSampleStep(row.status)

  async function advance() {
    if (!next || busy) return
    setBusy(true)
    try {
      const updated = await updateSampleStatus(row.id, next.status)
      onUpdated({ ...row, ...updated, status: next.status })
    } catch (error) {
      console.error(error)
    } finally {
      setBusy(false)
    }
  }

  return (
    <article className="rounded-lg border p-4" style={{ borderColor: '#EAEEF5' }}>
      <div className="flex items-start justify-between gap-4">
        <div className="min-w-0">
          <h2 className="line-clamp-1 text-[14px] font-bold" style={{ color: '#1B2840' }}>
            {summary ? [summary.code, summary.title].filter(Boolean).join(' · ') : 'No product linked'}
          </h2>
          <p className="mt-1 line-clamp-1 text-[12.5px]" style={{ color: '#5A6883' }}>
            {[summary?.businessUnit, summary?.retailerName, summary?.buyerName, relationName(row.factory)].filter(Boolean).join(' · ') || relationName(row.project)}
          </p>
        </div>
        <span className="shrink-0 rounded-md px-2 py-0.5 text-[11px] font-bold" style={{ background: status.bg, color: status.color }}>
          {titleCase(row.status)}
        </span>
      </div>

      <div className="mt-4 grid grid-cols-4 gap-2 text-[12px]">
        <Fact label="Type" value={titleCase(row.sample_type)} />
        <Fact label="Requested" value={formatDate(row.requested_at)} />
        <Fact label="Expected" value={formatDate(row.expected_at)} />
        <Fact label="Received" value={formatDate(row.received_at)} />
      </div>

      <div className="mt-3 grid grid-cols-2 gap-2 text-[12px]">
        <Fact label="Buyer sent" value={formatDate(row.sent_to_buyer_at)} />
        <Fact label="Licensor sent" value={formatDate(row.sent_to_licensor_at)} />
      </div>

      <div className="mt-3 flex flex-wrap items-center gap-2 text-[12px]" style={{ color: '#5A6883' }}>
        <span className="inline-flex items-center gap-1">
          <Factory className="size-3.5" />
          {relationName(row.factory) ?? 'No factory'}
        </span>
        <span>{userName(row.requested_by) ? `Requested by ${userName(row.requested_by)}` : 'No requester'}</span>
        {(row.primary_photo || row.photo_urls) && (
          <span className="inline-flex items-center gap-1">
            <Camera className="size-3.5" />
            Photo proof
          </span>
        )}
      </div>

      {row.revision_required && (
        <div className="mt-3 rounded-md px-3 py-2 text-[12.5px]" style={{ background: '#FBE2D8', color: '#9E3B1C' }}>
          <span className="inline-flex items-center gap-1 font-bold"><TriangleAlert className="size-3.5" /> Revision required</span>
          {row.revision_reason && <p className="mt-1">{row.revision_reason}</p>}
        </div>
      )}

      <div className="mt-4 flex justify-end">
        {next ? (
          <button
            type="button"
            onClick={advance}
            disabled={busy}
            className="inline-flex h-8 items-center gap-1 rounded-lg border px-2.5 text-[12px] font-bold transition-colors hover:bg-[#F6F8FC] disabled:opacity-50"
            style={{ borderColor: '#EAEEF5', color: '#1B2840' }}
          >
            <ArrowRight className="size-3.5" />
            {busy ? 'Saving...' : next.label}
          </button>
        ) : (
          <span className="text-[12px]" style={{ color: '#94A0B5' }}>No next step</span>
        )}
      </div>
    </article>
  )
}

function Fact({ label, value }: { label: string; value: string }) {
  return (
    <div className="min-w-0 rounded-md px-2 py-1.5" style={{ background: '#F6F8FC' }}>
      <div className="text-[10.5px] font-bold uppercase tracking-[0.04em]" style={{ color: '#94A0B5' }}>{label}</div>
